 1	import * as React from 'react';
 2	import { Button, Popover, PopoverProps } from '@patternfly/react-core';
 3	import { OutlinedQuestionCircleIcon } from '@patternfly/react-icons';
 4	import { useCustomTranslation } from '../useCustomTranslationHook';
 5	import './field-level-help.scss';
 6	
 7	export const FieldLevelHelp: React.FC<FieldLevelHelpProps> = React.memo(
 8	  ({ children, popoverHasAutoWidth, testId, position, buttonText }) => {
 9	    const { t } = useCustomTranslation();
10	    if (React.Children.count(children) === 0) {
11	      return null;
12	    }
13	    return (
14	      <Popover
15	        aria-label={t('Help')}
16	        bodyContent={children}
17	        hasAutoWidth={popoverHasAutoWidth}
18	        position={position}
19	      >
20	        <Button
21	          aria-label={t('Help')}
22	          variant="link"
23	          isInline
24	          className="odf-field-level-help"
25	          data-test-id={testId || null}
26	        >
27	          {!!buttonText && buttonText + ' '}
28	          <OutlinedQuestionCircleIcon className="odf-field-level-help__icon" />
29	        </Button>
30	      </Popover>
31	    );
32	  }
33	);
34	
35	FieldLevelHelp.displayName = 'FiledLevelHelp';
36	
37	type FieldLevelHelpProps = {
38	  children: React.ReactNode;
39	  popoverHasAutoWidth?: PopoverProps['hasAutoWidth'];
40	  testId?: string;
41	  position?: PopoverProps['position'];
42	  buttonText?: string;
43	};

